1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type Damage = { itemType: string; amount: number };
9	export type Incident = { cause: string; damages: Damage[] };
10	export type QuoteStep = { op: "quote"; items: Item[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	export type QuoteResult = { premium: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	export type ScenarioResult = { results: (QuoteResult | ClaimResult)[] };
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const baseFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
31	
32	const BLOCK_OF_3_PREMIUM = 60;
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
36	
37	const componentBlockBase = (count: number, type: string): number =>
38	  count === 3 ? BLOCK_OF_3_PREMIUM : count * baseFor({ type });
39	
40	const componentsBase = (components: Item[]): number => {
41	  const countsByType = components.reduce<Record<string, number>>((counts, item) => {
42	    counts[item.type] = (counts[item.type] ?? 0) + 1;
43	    return counts;
44	  }, {});
45	  return Object.entries(countsByType).reduce(
46	    (sum, [type, count]) => sum + componentBlockBase(count, type),
47	    0,
48	  );
49	};
50	
51	const sumBasePremiums = (items: Item[]): number => {
52	  const components = items.filter(isComponent);
53	  const nonComponents = items.filter((i) => !isComponent(i));
54	  const nonComponentsBase = nonComponents.reduce((sum, item) => sum + baseFor(item), 0);
55	  return componentsBase(components) + nonComponentsBase;
56	};
57	
58	const CURSE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_RATE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	
62	const isCursed = (item: Item): boolean => item.cursed === true;
63	const hasHighEnchantment = (item: Item): boolean =>
64	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
65	
66	const surchargeFor = (item: Item): number => {
67	  const base = baseFor(item);
68	  const curse = isCursed(item) ? base * CURSE_RATE : 0;
69	  const highEnch = hasHighEnchantment(item) ? base * HIGH_ENCHANTMENT_RATE : 0;
70	  return curse + highEnch;
71	};
72	
73	const itemSurcharges = (items: Item[]): number =>
74	  items.reduce((sum, item) => sum + surchargeFor(item), 0);
75	
76	const LOYALTY_RATE = 0.2;
77	const LOYALTY_THRESHOLD_YEARS = 2;
78	
79	const isLoyal = (customer: Customer): boolean =>
80	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
81	
82	const quotePremium = (items: Item[], customer: Customer): number => {
83	  const itemsBase = sumBasePremiums(items);
84	  const surcharges = itemSurcharges(items);
85	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
86	  const loyalty = isLoyal(customer) ? itemsBase * LOYALTY_RATE : 0;
87	  return Math.ceil(itemsBase + surcharges + firstInsurance - loyalty + PROCESSING_FEE);
88	};
89	
90	export const runScenario = (scenario: Scenario): ScenarioResult => {
91	  const results = scenario.steps.map((step) => {
92	    if (step.op === "quote") return { premium: quotePremium(step.items, scenario.customer) };
93	    return { payout: 0, remainingCap: 0 };
94	  });
95	  return { results };
96	};
